const _equipment_weaponenhancements = {title: "Weapon Enhancements", jsx: <IonList lines="full"><IonItem className="mainItem basic"><IonLabel><p><InnerLink toTop to="main-equipment_weaponenhancements-wenhancetables">Jump to the table</InnerLink></p>
</IonLabel></IonItem><IonItem className="mainItem basic"><IonLabel><p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2</Link><br/>Some smiths or inventive adventurers are unsatisfied with traditional weapon designs, adding custom improvements to the weapons they craft. These modifications are added to mundane weapons after creation at the listed cost, but modifying magical weapons increases the cost of modifications by 50%. As with enchanting, modifications are applied to ammunition in sets of 50. A weapon can normally only bear one modification at a time.</p>
<p>After being modified, a weapon's category (simple, martial, or exotic) increases by one step. While a character proficient with all martial weapons can use a modified simple weapon without additional training, modified martial weapons require the <Link to="/feat/exotic_weapon_proficiency">Exotic Weapon Proficiency</Link> feat to use without taking penalties. An exotic weapon that receives modifications cannot be wielded without the <Link to="/feat/modified_weapon_proficiency">Modified Weapon Proficiency</Link> or <Link to="/feat/weapon_adept">Weapon Adept</Link> feat. A character proficient with a specific weapon (such as a cleric's proficiency with her deity's favored weapon) is not automatically proficient with a modified weapon of that type.</p>
</IonLabel></IonItem><IonItemDivider className="mainItem" id="main-equipment_weaponenhancements-wenhancetables"><IonLabel>Table</IonLabel></IonItemDivider><IonItem className="mainItem basic"><IonLabel><DisplayTable table={{"id":"weapon modifications","columns":[{"header":"Name","align":"start","link":"eq-weaponenh"},{"header":"Cost Adjustment","type":"gp+"},{"header":"Weight Adjustment","type":"lbs+"}],"data":[[["sawback sword","sawback_sword"],5,{"sort":0}],[["consecrated weapon","consecrated_weapon"],150,{"sort":0}],[["undine weaponshaft","undine_weaponshaft"],300,{"sort":0}],[["versatile design","versatile_design"],500,{"sort":0}],[["jagged hooks","jagged_hooks"],1000,1],[["razor-sharp","razor_sharp"],1000,{"sort":0}],[["brutally weighted","brutally_weighted"],1500,1],[["dual-balanced","dual_balanced"],2000,{"sort":0}],[["serrated edge","serrated_edge"],2000,{"sort":0}],[["tactically adapted","tactically_adapted"],2000,{"sort":0}]],"initialColumn":1}} />
</IonLabel></IonItem></IonList>};
